sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;

    var soldDate = g_form.getValue('date_sold_on');
    var months = g_form.getValue('warranty_period_months_choice');
    var expiryField = 'warranty_expiring_at';

    // Ensure both fields are populated and expiry date is empty
    if (!soldDate || !months || g_form.getValue(expiryField)) return;

    months = parseInt(months);
    if (isNaN(months)) return;

    var startDate = new Date(soldDate);
    startDate.setMonth(startDate.getMonth() + months);

    // Format date to yyyy-MM-dd HH:mm:ss
    var formattedDate = startDate.getFullYear() + '-' +
        String(startDate.getMonth() + 1).padStart(2, '0') + '-' +
        String(startDate.getDate()).padStart(2, '0') + ' ' +
        String(startDate.getHours()).padStart(2, '0') + ':' +
        String(startDate.getMinutes()).padStart(2, '0') + ':' +
        String(startDate.getSeconds()).padStart(2, '0');

    g_form.setValue(expiryField, formattedDate);
}
